        encoded = json.dumps(summary, ensure_ascii=False)
        self.assertNotIn("raw_artifact", encoded)
        self.assertNotIn("checksum", encoded)
        self.assertNotIn("/tmp/raw.json", encoded)
        self.assertNotIn("/cmd_vel", encoded)
